  ('police-3fd24912-moex-00140', 'police-3fd24912', 'police-3fd24912-moex-113-cd698155', 'sub-police-3fd24912-03', NULL, 'essay', '依據「國家機密保護法」，應如何保護國家機密之複製物？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "f6fdea516605", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "504", "s": "1207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國家安全情報法制", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL),
