  ('police-3fd24912-moex-00148', 'police-3fd24912', 'police-3fd24912-moex-112-15a7b19c', 'sub-police-3fd24912-01', NULL, 'single_choice', '下列有關憲法工作權之敘述，何者正確？', '["公務員甲在假日期間至行天宮兼職擔任算命師貼補家用，不屬於工作權保障範圍", "法律規定計程車駕駛必須經考試取得執業證照，屬於對工作權之客觀許可條件之限制", "法律規定律師出庭應穿律師袍，係屬於對職業執行方式之限制", "人民失業有請求國家給予適當工作之權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:59+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "504", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "公共安全人員"}'::jsonb, NULL)
